'use client';

import { motion } from 'framer-motion';
import { useInView } from 'framer-motion';
import { useRef } from 'react';

const agendaImg = 'data:image/png;base64,';
const dashImg   = 'data:image/png;base64,';
const clienteImg= 'data:image/png;base64,';
const servicoImg= 'data:image/png;base64,';
const relImg    = 'data:image/png;base64,';

const demoCards = [
  { icon: '📅', title: 'Agenda Principal',       desc: 'Visualização mensal e diária com horários organizados e status de cada atendimento em tempo real.', src: agendaImg,  col: 'top' },
  { icon: '⚙️', title: 'Painel Administrativo', desc: 'Controle de faturamento, ticket médio, agendamentos e resumo financeiro do período.',               src: dashImg,    col: 'top' },
  { icon: '👥', title: 'Cadastro de Clientes',  desc: 'Gerencie clientes com contato, plano e histórico de atendimentos em um só lugar.',                  src: clienteImg, col: 'top' },
  { icon: '🛠️', title: 'Cadastro de Serviços', desc: 'Configure serviços com duração e valor — simples e visual com ativação por toggle.',                  src: servicoImg, col: 'bot' },
  { icon: '📊', title: 'Relatório por Profissional', desc: 'Faturamento, atendimentos finalizados e ticket médio por profissional no período.',             src: relImg,     col: 'bot' },
];

function Card({ card, i, inView }: { card: typeof demoCards[0]; i: number; inView: boolean }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 24 }}
      animate={inView ? { opacity: 1, y: 0 } : {}}
      transition={{ duration: 0.6, delay: i * 0.08 }}
      style={{
        background: '#fff',
        border: '1px solid var(--border)',
        borderRadius: '14px',
        overflow: 'hidden',
        boxShadow: '0 1px 3px rgba(0,0,0,0.05)',
        transition: 'all 0.3s',
        cursor: 'default',
      }}
      whileHover={{ y: -5, boxShadow: '0 8px 24px rgba(0,0,0,.10)', borderColor: 'var(--border-2)' }}
    >
      {/* Header */}
      <div style={{ background: 'var(--bg-2)', padding: '.85rem 1.1rem', display: 'flex', alignItems: 'center', gap: '.65rem', borderBottom: '1px solid var(--border)' }}>
        <div style={{ width: 30, height: 30, background: 'var(--accent-light)', borderRadius: '7px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '.9rem', flexShrink: 0 }}>
          {card.icon}
        </div>
        <span style={{ fontFamily: 'var(--font-display)', fontSize: '.87rem', fontWeight: 600, color: 'var(--text)' }}>{card.title}</span>
      </div>

      {/* Screenshot */}
      <div style={{ background: 'var(--bg-2)', padding: '.65rem', borderBottom: '1px solid var(--border)', overflow: 'hidden' }}>
        <img
          src={card.src}
          alt={card.title}
          style={{ width: '100%', borderRadius: '8px', display: 'block', border: '1px solid var(--border)', objectFit: 'cover', objectPosition: 'top', maxHeight: '160px' }}
        />
      </div>

      {/* Description */}
      <div style={{ padding: '.9rem 1.1rem' }}>
        <p style={{ fontSize: '.82rem', color: 'var(--text-2)', lineHeight: 1.7, fontWeight: 300 }}>{card.desc}</p>
      </div>
    </motion.div>
  );
}

export default function SystemDemo() {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: '-80px' });

  const topCards = demoCards.filter(c => c.col === 'top');
  const botCards = demoCards.filter(c => c.col === 'bot');

  return (
    <section id="sistema" style={{ padding: 'clamp(3rem,8vw,5.5rem) clamp(1rem,4vw,2rem)' }}>
      <div className="container" ref={ref}>
        <motion.div initial={{ opacity: 0, y: 24 }} animate={inView ? { opacity: 1, y: 0 } : {}} transition={{ duration: 0.65 }}>
          <div className="section-label">Demonstração</div>
          <h2 className="section-title">Veja o sistema em ação</h2>
          <p className="section-sub">Telas reais do sistema — intuitivas e organizadas, pensadas para o dia a dia da sua empresa.</p>
        </motion.div>

        {/* Top row — 3 cards */}
        <div className="demo-grid-top">
          {topCards.map((card, i) => <Card key={card.title} card={card} i={i} inView={inView} />)}
        </div>

        {/* Bottom row — 2 cards */}
        <div className="demo-grid-bot">
          {botCards.map((card, i) => <Card key={card.title} card={card} i={i + topCards.length} inView={inView} />)}
        </div>
      </div>
    </section>
  );
}
